describe('managed + in-sync unreadable code (configured-PIN proxy)', () => {
    const proxySlot = {
        slot: 1,
        code: 'unreadable_code',
        managed: true,
        in_sync: true,
    };

    it('masks to the configured length, not a fixed 3 dots', () => {
        expect((card as any)._revealed).toBe(false);
        expect(
            (card as any)._formatCode({ ...proxySlot, configured_code_length: 4 })
        ).toBe('••••');
        expect((card as any)._getCodeClass({ ...proxySlot, configured_code_length: 4 })).toBe(
